import{_ as a,o as t,c as r,ag as o}from"./chunks/framework.DXGyWiRo.js";const m=JSON.parse('{"title":"Parameters Page","description":"","frontmatter":{},"headers":[],"relativePath":"robotics/parameters-page.md","filePath":"robotics/parameters-page.md"}'),i={name:"robotics/parameters-page.md"};function l(s,e,h,n,d,f){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="parameters-page" tabindex="-1">Parameters Page <a class="header-anchor" href="#parameters-page" aria-label="Permalink to &quot;Parameters Page&quot;">​</a></h1><p>The Parameters page allows users to find and modify any of the parameters associated with the vehicle.</p><p>A list with a description of what each parameter does is listed in the Developers: Full Parameters List.</p><h2 id="finding-a-parameter" tabindex="-1">Finding a Parameter <a href="#finding-a-parameter" id="finding-a-parameter"></a> <a class="header-anchor" href="#finding-a-parameter" aria-label="Permalink to &quot;Finding a Parameter &lt;a href=&quot;#finding-a-parameter&quot; id=&quot;finding-a-parameter&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>The parameters are organized in groups. Select a group of parameters to view by clicking on the buttons to the left.</p><p>You can also search for a parameter by entering a term in the <em>Search</em> field. This will show you a list of all parameter names and descriptions that contain the entered substring (press <em>Clear</em> to reset the search).</p><h3 id="changing-a-parameter" tabindex="-1">Changing a Parameter <a href="#changing-a-parameter" id="changing-a-parameter"></a> <a class="header-anchor" href="#changing-a-parameter" aria-label="Permalink to &quot;Changing a Parameter &lt;a href=&quot;#changing-a-parameter&quot; id=&quot;changing-a-parameter&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>To change the value of a parameter click on the parameter row in a group or search list. This will open a side dialog in which you can update the value (this dialog also provides additional detailed information about the parameter - including whether a reboot is required for the change to take effect).</p><p>You can select additional options from the <em>Tools</em> menu on the top right hand side of the screen.</p><h4 id="refresh" tabindex="-1">Refresh <a href="#refresh" id="refresh"></a> <a class="header-anchor" href="#refresh" aria-label="Permalink to &quot;Refresh &lt;a href=&quot;#refresh&quot; id=&quot;refresh&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>Refresh the parameter values by re-requesting all of them from the vehicle.</p><h4 id="reset-all-to-defaults" tabindex="-1">Reset all to defaults <a href="#reset-all-to-defaults" id="reset-all-to-defaults"></a> <a class="header-anchor" href="#reset-all-to-defaults" aria-label="Permalink to &quot;Reset all to defaults &lt;a href=&quot;#reset-all-to-defaults&quot; id=&quot;reset-all-to-defaults&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>Reset all parameters to their original default values.</p><h4 id="load-from-file-save-to-file" tabindex="-1">Load from file / Save to file <a href="#load-from-file--save-to-file" id="load-from-file--save-to-file"></a> <a class="header-anchor" href="#load-from-file-save-to-file" aria-label="Permalink to &quot;Load from file / Save to file &lt;a href=&quot;#load-from-file--save-to-file&quot; id=&quot;load-from-file--save-to-file&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>Load parameters from an existing file or save your current parameter settings to a file on the topside computer.</p><h4 id="reboot-vehicle" tabindex="-1">Reboot Vehicle <a href="#reboot-vehicle" id="reboot-vehicle"></a> <a class="header-anchor" href="#reboot-vehicle" aria-label="Permalink to &quot;Reboot Vehicle &lt;a href=&quot;#reboot-vehicle&quot; id=&quot;reboot-vehicle&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>Reboot the vehicle (required after changing some parameters).</p><h3 id="results-matching" tabindex="-1">results matching &quot;&quot; <a class="header-anchor" href="#results-matching" aria-label="Permalink to &quot;results matching &quot;&quot;&quot;">​</a></h3><ul><li></li></ul><h3 id="no-results-matching" tabindex="-1">No results matching &quot;&quot; <a class="header-anchor" href="#no-results-matching" aria-label="Permalink to &quot;No results matching &quot;&quot;&quot;">​</a></h3>',20)])])}const c=a(i,[["render",l]]);export{m as __pageData,c as default};
